#include <stdio.h>
#include <math.h>

#define W 2400
#define H 1800

static double CX=0.0, CY=1.0/3.0, CZ=-5.0/3.0, R=1.0/3.0;

/* nearest sphere hit t>eps along origin o + dir d, returns t or -1 */
static double hitsphere(double ox,double oy,double oz,double dx,double dy,double dz){
    double ocx=ox-CX, ocy=oy-CY, ocz=oz-CZ;
    double a=dx*dx+dy*dy+dz*dz;
    double b=2.0*(ocx*dx+ocy*dy+ocz*dz);
    double c=ocx*ocx+ocy*ocy+ocz*ocz-R*R;
    double disc=b*b-4.0*a*c;
    if(disc<0.0) return -1.0;
    double t=(-b-sqrt(disc))/(2.0*a);
    if(t>1e-4) return t;
    return -1.0;
}

int main(void){
    double vh=2.0, vw=(double)W/(double)H*vh;
    double ox=0.0, oy=0.5, oz=0.0;
    double ln=sqrt(3.0), Lx=1.0/ln, Ly=1.0/ln, Lz=-1.0/ln;
    double sc=3.0;
    FILE*f=fopen("reconstructed.ppm","w");
    fprintf(f,"P3\n%d %d\n255\n",W,H);
    for(int j=0;j<H;j++){
        double t=1.0-(double)j/(double)(H-1);
        double dy=(t-0.5)*vh;
        for(int i=0;i<W;i++){
            double s=(double)i/(double)(W-1);
            double dx=(s-0.5)*vw, dz=-1.0;
            double cr,cg,cb;
            double ts=hitsphere(ox,oy,oz,dx,dy,dz);
            double tp=(dy<-1e-9)?(-oy/dy):1e30;
            if(ts>0.0 && (ts<tp)){
                double px=ox+ts*dx, py=oy+ts*dy, pz=oz+ts*dz;
                double nx=(px-CX)/R, ny=(py-CY)/R, nz=(pz-CZ)/R;
                double nl=nx*Lx+ny*Ly+nz*Lz; if(nl<0.0) nl=0.0;
                double sh=0.2+0.8*nl;
                cr=1.0*sh; cg=0.2*sh; cb=0.2*sh;
            } else if(tp<1e29){
                double qx=ox+tp*dx, qz=oz+tp*dz;
                long par=((long)floor(qx*sc)+(long)floor(qz*sc))&1L;
                double alb=par?0.4:0.9;
                double sd=hitsphere(qx,0.0,qz,Lx,Ly,Lz);
                double sh=(sd>0.0)?0.2:(0.2+0.8*Ly);
                cr=cg=cb=alb*sh;
            } else {
                double nn=sqrt(dx*dx+dy*dy+dz*dz);
                double uy=dy/nn, ts2=0.5*(uy+1.0);
                cr=1.0-0.5*ts2; cg=1.0-0.3*ts2; cb=1.0;
            }
            if(cr>0.999999)cr=0.999999; if(cg>0.999999)cg=0.999999; if(cb>0.999999)cb=0.999999;
            if(cr<0)cr=0; if(cg<0)cg=0; if(cb<0)cb=0;
            fprintf(f,"%d %d %d\n",(int)(cr*255.99),(int)(cg*255.99),(int)(cb*255.99));
        }
    }
    fclose(f);
    return 0;
}

